-- Query 1: category equality + price order
CREATE INDEX idx_cat_price ON products(category, price);
-- category filters rows, price is pre-sorted within category → no filesort

-- Query 2: seller_id equality + price range
CREATE INDEX idx_seller_price ON products(seller_id, price);
-- equality (seller_id) before range (price) — leftmost prefix rule

-- Query 3: covering index for SELECT name, price WHERE category
CREATE INDEX idx_cat_covering ON products(category, name, price);
-- Extra: Using index in EXPLAIN — zero heap access for this query

-- Query 4: range on created_at
CREATE INDEX idx_created ON products(created_at);
-- Simple single-column range index
